#include<bits/stdc++.h>

using namespace std;

int ab(int a)

{

    if(a<0)

        return -a;

    return a;

}

int dis(int a,int b,int c,int d)

{

    return ab(a-c)+ab(b-d);

}

int main()

{

    int n;

    int m;

    scanf("%d %d",&n,&m);

    int a[n],b[n],c[m],d[m];

    for(int i=0;i<n;i++)

        scanf("%d %d",a+i,b+i);

    for(int i=0;i<m;i++)

        scanf("%d %d",c+i,d+i);

    for(int i=0;i<n;i++)

    {

        int sr[m];

        for(int j=0;j<m;j++)

            sr[j]=dis(a[i],b[i],c[j],d[j]);

        int mini=sr[0];

        for(int j=1;j<m;j++)

            if(mini>sr[j])

            mini=sr[j];

        for(int j=0;j<m;j++)

            if(sr[j]==mini)

        {

            printf("%d\n",j+1);

            break;

        }

    }

    return 0;

}

